export function getElement(symbolOrNumber: string | number): Element | undefined {
  if (typeof symbolOrNumber === "number") {
    return elements.find(e => e.atomicNumber === symbolOrNumber);
  }
  return elements.find(
    e => e.symbol.toLowerCase() === symbolOrNumber.toLowerCase() ||
         e.name.toLowerCase() === symbolOrNumber.toLowerCase()
  );
}

export function getElementsByCategory(category: ElementCategory): Element[] {
  return elements.filter(e => e.category === category);
}

